var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"노르드나빅 왕국 변경.  \\n왕립 국경수비대 관할 남단 산악국경지대.","JPN":"ノルドナビック王国の辺境。\\n王立国境守備隊管轄の南端山岳国境地帯。","ENG":"The Kingdom of Nordnavik.\\nThe southernmost mountainous border of the Royal Border Guards.","TWN":"諾爾德萊比王國邊境 \\n皇室國境護衛隊管轄南方山岳國境地區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"셔우드 외성.  \\n보류 환자 거주 구역.","JPN":"シャーウッド外郭。\\n保留患者の居住区域。","ENG":"Outer castle Sherwood.\\nReserved Patient Zone.","TWN":"休烏特外城 \\n保留患者居住區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"상태는 어떠냐?","JPN":"状態はどうだ？","ENG":"How are things looking?","TWN":"狀態如何？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"침식된 흔적은 없어요. 적어도 겉으로 보기엔.","JPN":"侵食された跡はありません。少なくとも見た目は。","ENG":"No signs of Corruption. Well, at least on the outside.","TWN":"至少表面上看起來沒有遭受侵蝕的跡象。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"간만에 아주 실하네요. 도시에다 팔아도 되겠는데요?","JPN":"久々によく育ちましたね。都市で売ってもよさそうじゃないですか？","ENG":"It's been a long time since we had such good yield. I think we might even be able to sell them in the city.","TWN":"好久沒遇到這麼漂亮的，可以賣到城裡嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"나 참, 환자 구역에서 키운 감자를 누가 사? 돌이나 안 맞으면 다행이지.","JPN":"まったく、患者区域で育てたジャガイモを誰が買うというんじゃ？　石を投げられないだけマシじゃろうて。","ENG":"*Scoff* Who would want to buy potatoes grown here? We'd be lucky to get out of the city unscathed.","TWN":"你也真是的，誰會買病患區出產的馬鈴薯？你是想被石頭砸嗎。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ONIL_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"음? 눈이 내리네요?","JPN":"うむ？　雪が降ってますね。","ENG":"Hmm? It's snowing?","TWN":"嗯？下雪咧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L13_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"그래. 또 어디서 거지 같은 일이 벌어지려나 보구나.","JPN":"ああ。またどこかでくだらんことでも起こりそうじゃな。","ENG":"It is. I guess something terrible is about to happen.","TWN":"是啊，看來又有壞事要發生了。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"침식체가 나타날지도 몰라요. 수비대에 알릴까요?","JPN":"侵食体が現れるかもしれません。守備隊に知らせましょうか？","ENG":"C.O.s might appear. Should I alert the guards?","TWN":"不知道會不會出現侵蝕體，要告訴護衛隊嗎？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"엘라 대장 모르게 와트한테 귀띔만 해 줘.","JPN":"エラ隊長に悟られぬようワットに耳打ちだけしてやれ。","ENG":"Tell Watt, but make sure it doesn't get into Captain Ella's ears.","TWN":"偷偷透露風聲給華特就好，別讓艾拉隊長知道。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"지난번에 화약 때문에 난 상처가 다 낫지도 않았을 텐데. 괜히 또 덧날라.","JPN":"この前火薬のせいで負った傷がまだ治ってないはずじゃ。こじれたら困るからのう。","ENG":"She still hasn't recovered from that wound she got from the gunpowder last time. It will only delay her healing.","TWN":"上次因爲火藥而引發的傷口都還沒好呢，我擔心她又舊疾復發。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"에이, 그래도 명색이 카운터인데 괜찮겠죠.","JPN":"いやぁ、でもカウンターですから大丈夫でしょう。","ENG":"But she's still a Counter. I'm sure she'll be all right.","TWN":"哎唷，她再怎麼說也是個制裁者，應該沒問題吧？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"인석아, 탈나면 어쩌려고? 그 사람 말고 어느 카운터가 우리까지 지켜 주겠냐?","JPN":"このやろ、病気になった時どうするんじゃ。あの人をおいてわしらを守ってくれるカウンターはおらんじゃろう？","ENG":"You brat. What if something bad happened to her? What other Counter do you think is willing to protect us, hmm?","TWN":"你這傢伙，有個什麼萬一的話怎麼辦？你覺得除了她，還有哪個制裁者會保護我們？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"쓸데없는 소리 그만하고 와트나 찾아가.","JPN":"くだらんこと言わんで、ワットのところに行きなさい。","ENG":"Stop your nonsense and go find Watt.","TWN":"廢話少說，快去找華特吧。"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"……어?","JPN":"……あ？","ENG":"...Huh?","TWN":"……呃？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"또 왜?","JPN":"またなんじゃ？","ENG":"What now?","TWN":"你又幹嘛？"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"침식체다! 이쪽으로 오고 있어요!","JPN":"侵食体だ！　こちらに向かってます！","ENG":"C.O.s! They're coming this way!","TWN":"是侵蝕體！正往這邊來！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NULL","text":{"KOREA":"이런! 어서 경보 울려!","JPN":"しまった！　早く警報を鳴らしなさい！","ENG":"Dammit! Sound the alarms!","TWN":"糟糕！快發出警報！"},"stage":{"bg":"NOMAD_VILLAGE","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_BORDER_NULL_ELITE","text":{"KOREA":"1종 소형 침식체 다수의 접근 확인! 제1격대 사격 준비!","JPN":"多数の第1種小型侵食体が接近中！　第1撃隊、射撃準備！","ENG":"Multiple small Category 1 C.O.s approaching confirmed! 1st squadron, get ready to fire!","TWN":"確認有大量1類小型侵蝕體接近中！第1射擊隊預備！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_ELITE","face":"UNIT_IDLE"},"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"GUARD_BORDER_NULL_ELITE","text":{"KOREA":"발사!","JPN":"発射！","ENG":"FIRE!","TWN":"發射！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_ELITE","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"GUARD_BORDER_NULL_ELITE","text":{"KOREA":"제2격대 사격 준비!","JPN":"第2撃隊、射撃準備！","ENG":"2nd strike unit, aim!","TWN":"第2射擊隊預備！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_ELITE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GUARD_BORDER_NULL_ELITE","text":{"KOREA":"발사!","JPN":"発射！","ENG":"FIRE!","TWN":"發射！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_ELITE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"……이걸로 끝인가?","JPN":"……これで終わりか？","ENG":"Is that all of them...?","TWN":"……結束啦？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PITER_BORDER_NULL_NULL","text":{"KOREA":"뭐야. 괜히 쫄았네.","JPN":"なんだ。ビビったじゃねえか。","ENG":"Wait, that's it?","TWN":"什麼嘛，白擔心一場！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_BORDER_NULL_ELITE","text":{"KOREA":"물러서라, 피터. 눈이 아직 그치지 않았어.","JPN":"下がってろ、ピーター。まだ雪が止んでねえぞ。","ENG":"Stand back, Peter. It's still snowing.","TWN":"彼得，等等，雪還沒停呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_ELITE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"알겠어요, 와트 씨.","JPN":"わかりました、ワットさん。","ENG":"Okay, Mr. Watt.","TWN":"是，華特先生。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_ELITE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"전원, 장전하고 각자 위치에서 대기한다!","JPN":"総員、装填して各自の位置で待機しろ！","ENG":"Men, reload and hold your positions!","TWN":"全員填裝子彈，各就各位！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh…?","TWN":"嗯……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"와트 씨, 저기 보이는 거 사람 아니에요?","JPN":"ワットさん、あそこに見えるの、人じゃないですか？","ENG":"Mr. Watt! Isn't that a person over there?","TWN":"華特先生，那不是人嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"뭐? 네가 눈이 좋은 건 안다만 뭘 잘못 본 거 아니냐?","JPN":"は？　お前の目がいいのは知ってるが、見間違いじゃねえか？","ENG":"What? I know you’ve got great vision, but are you sure about that?","TWN":"什麼？我知道你視力很好，但你是不是看錯？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"국경 밖에서 사람이 오는 경우는 그동안 한 번도 없었어.","JPN":"今まで国境の外から人が来たことは一度もなかったぞ。","ENG":"There’s never been a person coming over from the other side of the border.","TWN":"這段時間完全沒有人在國境出沒。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"아뇨. 정말이에요. 말 같은 걸 타고 있어요.","JPN":"いや。本当ですって。馬みたいなのに乗ってますよ。","ENG":"No, I saw right. He was riding a horse or something of the like.","TWN":"不，是真的。好像還騎著馬。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"그리고…… 뭔가에 쫓기고 있는 것 같은데요?","JPN":"あと……何かに追われてるみたいなんですけど？","ENG":"And... It looked as if something was chasing him.","TWN":"而且……似乎在被什麼東西追趕的樣子？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"하이랜더 타입이 접근 중입니다!","JPN":"ハイランダータイプが接近中です！","ENG":"Highlander-Type, approaching!","TWN":"高地闊步者類型接近中！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"하이랜더? 오늘 국경에서 침식체들 잔치판이라도 열리는 건가?","JPN":"ハイランダー？　今日は国境で侵食体の祭りでもあんのか？","ENG":"A Highlander? Is there a C.O. party at the border I don't know about?","TWN":"高地闊步者？今天侵蝕體是在國境舉辦派對嗎？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"절대 외성 쪽으로 접근하게 두지 마라! 해자로 유인해!","JPN":"絶対に外郭に近づかせるな！　掘に誘導しろ！","ENG":"Don't let them approach the castle! Lure them to the moat!","TWN":"絕對不能它往外城的方向靠近！把它引到壕溝那裡！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"와트 씨! 거긴 지난번에 폭탄을 잔뜩 쌓아 둔 곳이잖아요!","JPN":"ワットさん！　あそこはこの前爆弾をいっぱい積んでおいた場所じゃないですか！","ENG":"But Mr. Watt! Isn't that where we stashed all the bombs?","TWN":"華特先生！那裡不是上次堆滿炸彈的地方嗎？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"그래. 이럴 때를 위해 준비한 싸구려들이지.","JPN":"そうだ。こういう時のために用意した安物さ。","ENG":"Yes. Those mediocre things were placed there for times like this.","TWN":"沒錯，就是為這種時候所預備的便宜貨！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PITER_BORDER_NULL_NAMED","text":{"KOREA":"쫓기는 사람은 어떡하고요? 폭발에 같이 휘말릴 텐데!","JPN":"追われている人はどうするんですか？　爆発に巻き込まれますよ！","ENG":"What about the people getting chased? They might get caught up in the explosion!","TWN":"那被追趕的人怎麼辦？他會被爆炸波及的！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"하이랜더는 우리가 가진 무기만으로 못 막아.","JPN":"ハイランダーは俺たちの武器だけでは食い止められねえ。","ENG":"We can't stop Highlanders with our current weapons.","TWN":"光憑我們有的武器是擋不住高地闊步者的。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"설령 네 말대로 사람이더라도, 한 명 구하자고 도박을 할 순 없다.","JPN":"たとえお前の言うとおり人だったとしても、一人を救うために博打を打つわけにはいかねえんだよ。","ENG":"Even if there are people caught in the blast like you said, I can't risk it all to save one person.","TWN":"就算真如你所說他是人，也不能因為要救一個人，而賭上所有人的性命。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"놈들을 해자 쪽으로 유인해.","JPN":"やつらを堀の方に誘導しろ。","ENG":"Lure them to the moat.","TWN":"把那些傢伙引到壕溝那裡去，"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"쫓기고 있는 쪽은 내가 알아서 처리하겠다.","JPN":"追われてる方は私が処理する。","ENG":"I'll take care of the one chasing the man.","TWN":"被追趕的人我來處理。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"엇? 대장님?!","JPN":"あれ？　隊長！？","ENG":"Huh? Captain?!","TWN":"嗯？隊長？！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"괜찮겠습니까. 아직 지난번 상처가 다 낫지도 않으셨을 텐데.","JPN":"大丈夫なんですか？　まだこの前の傷が治ってないはずですが。","ENG":"Are you sure? Your wounds haven't fully healed from last time.","TWN":"可以嗎？上次的傷都還沒痊癒呢？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 괜찮아. 엄호 부탁하지.","JPN":"私は大丈夫だ。援護を頼む。","ENG":"I'm all right. Cover me, will you?","TWN":"我沒事，掩護我！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"대, 대장님?!","JPN":"た、隊長！？","ENG":"C-captain!!","TWN":"隊…隊長？！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"이런……! 다들 대장님을 엄호해라!","JPN":"おっと……！　みんな、隊長を援護しろ！","ENG":"Damn! All hands! Protect our captain!","TWN":"可惡……！大家掩護隊長！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};